// csv-parser.ts

type CSVOptions = {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
};

interface CSVError {
  row: number;
  message: string;
}

interface CSVResult<T extends Record<string, any> = Record<string, any>> {
  headers: string[];
  rows: T[];
  errors: CSVError[];
  filter: (predicate: (row: T) => boolean) => T[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<any, T[]>;
}

interface ParseLineResult {
  fields: string[];
  error?: string;
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = '\n';

function parseLine(line: string, delimiter: string, quote: string): ParseLineResult {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;
  let error: string | undefined;

  while (i < line.length) {
    const char = line[i];

    if (char === quote) {
      const nextChar = line[i + 1];
      if (inQuotes && nextChar === quote) {
        current += quote;
        i += 2;
        continue;
      }

      inQuotes = !inQuotes;
      i += 1;
      continue;
    }

    if (!inQuotes && char === delimiter) {
      fields.push(current);
      current = '';
      i += 1;
      continue;
    }

    current += char;
    i += 1;
  }

  fields.push(current);

  if (inQuotes) {
    error = 'Unterminated quoted field';
  }

  return { fields, error };
}

function coerceValue(rawValue: string): any {
  const trimmed = rawValue.trim();

  if (trimmed.length === 0) {
    return null;
  }

  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  if (/^-?\d+(\.\d+)?$/.test(trimmed)) {
    const num = Number(trimmed);
    if (Number.isFinite(num)) {
      return num;
    }
  }

  return rawValue;
}

export function parseCSV<T extends Record<string, any> = Record<string, any>>(
  input: string,
  options?: CSVOptions,
): CSVResult<T> {
  const delimiter = options?.delimiter ?? DEFAULT_DELIMITER;
  const quote = options?.quote ?? DEFAULT_QUOTE;
  const lineSeparator = options?.lineSeparator ?? DEFAULT_LINE_SEPARATOR;

  if (!input) {
    const empty: CSVResult<T> = {
      headers: [],
      rows: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return empty;
  }

  const rawLines = input.split(lineSeparator);
  const lines = rawLines.map((line) => (lineSeparator === '\n' ? line.replace(/\r$/, '') : line));

  if (lines.length === 0) {
    return {
      headers: [],
      rows: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const errors: CSVError[] = [];
  const headerLine = lines[0];
  const headerParse = parseLine(headerLine, delimiter, quote);
  const headers = headerParse.fields;

  if (headerParse.error) {
    errors.push({ row: 1, message: headerParse.error });
  }

  const rows: T[] = [];

  for (let index = 1; index < lines.length; index += 1) {
    const line = lines[index];
    const rowNumber = index + 1;

    if (line.length === 0 && index === lines.length - 1) {
      // skip trailing empty line
      continue;
    }

    const parsed = parseLine(line, delimiter, quote);

    if (parsed.error) {
      errors.push({ row: rowNumber, message: parsed.error });
      continue;
    }

    if (parsed.fields.length !== headers.length) {
      errors.push({ row: rowNumber, message: 'Malformed row: column count does not match headers' });
      continue;
    }

    const record: Record<string, any> = {};
    for (let i = 0; i < headers.length; i += 1) {
      record[headers[i]] = coerceValue(parsed.fields[i]);
    }

    rows.push(record as T);
  }

  const result: CSVResult<T> = {
    headers,
    rows,
    errors,
    filter: (predicate) => rows.filter(predicate),
    sum: (column: string) =>
      rows.reduce((acc, row) => {
        const value = row[column];
        return typeof value === 'number' ? acc + value : acc;
      }, 0),
    average: (column: string) => {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number') {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count: () => rows.length,
    groupBy: (column: string) => {
      const map = new Map<any, T[]>();
      for (const row of rows) {
        const key = row[column];
        const bucket = map.get(key);
        if (bucket) {
          bucket.push(row);
        } else {
          map.set(key, [row]);
        }
      }
      return map;
    },
  };

  return result;
}
