cat <<'EOF' > csv-parser.test.ts
import { parseCSV } from './csv-parser';

type TestFn = () => void;

function assert(condition: boolean, message?: string): void {
  if (!condition) {
    throw new Error(message || 'Assertion failed');
  }
}

function assertEqual<T>(actual: T, expected: T, message?: string): void {
  if (actual !== expected) {
    throw new Error(message || `Expected ${expected} but got ${actual}`);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message?: string): void {
  const stringify = JSON.stringify;
  if (stringify(actual) !== stringify(expected)) {
    throw new Error(message || `Deep equality failed: ${stringify(actual)} vs ${stringify(expected)}`);
  }
}

const tests: Array<{ name: string; fn: TestFn }> = [
  {
    name: 'basic parsing',
    fn: () => {
      const csv = 'name,age\nAlice,30\nBob,25';
      const result = parseCSV(csv);
      assertDeepEqual(result.headers, ['name', 'age']);
      assertEqual(result.rows.length, 2);
      assertEqual(result.count(), 2);
      assertEqual(result.errors.length, 0);
      assertEqual(result.rows[0].name, 'Alice');
      assertEqual(typeof result.rows[0].age, 'number');
      assertEqual(result.rows[0].age, 30);
    },
  },
  {
    name: 'quoted fields with commas',
    fn: () => {
      const csv = 'id,quote\n1,"Hello, world"\n2,"Another, piece"';
      const result = parseCSV(csv);
      assertEqual(result.rows[0].quote, 'Hello, world');
      assertEqual(result.rows[1].quote, 'Another, piece');
    },
  },
  {
    name: 'escaped quotes',
    fn: () => {
      const csv = 'id,message\n1,"He said ""hello"""';
      const result = parseCSV(csv);
      assertEqual(result.rows[0].message, 'He said "hello"');
    },
  },
  {
    name: 'custom delimiters and quotes',
    fn: () => {
      const csv = "id|note\n1|'a|b|c'\n2|'escape ''quotes'' test'";
      const result = parseCSV(csv, { delimiter: '|', quote: "'" });
      assertEqual(result.rows[0].note, 'a|b|c');
      assertEqual(result.rows[1].note, "escape 'quotes' test");
    },
  },
  {
    name: 'type coercion covers all types',
    fn: () => {
      const csv = 'number,boolTrue,boolFalse,nullVariant,empty,decimal,text\n123,TRUE,false,null,,45.67,keep';
      const result = parseCSV(csv);
      const row = result.rows[0];
      assertEqual(typeof row.number, 'number');
      assertEqual(row.number, 123);
      assertEqual(row.boolTrue, true);
      assertEqual(row.boolFalse, false);
      assertEqual(row.nullVariant, null);
      assertEqual(row.empty, null);
      assertEqual(row.decimal, 45.67);
      assertEqual(row.text, 'keep');
    },
  },
  {
    name: 'malformed row error collection',
    fn: () => {
      const csv = 'a,b\n1,2\n3';
      const result = parseCSV(csv);
      assertEqual(result.rows.length, 1);
      assertEqual(result.errors.length, 1);
      assertEqual(result.errors[0].row, 3);
      assert(result.errors[0].message.includes('column count'));
    },
  },
  {
    name: 'filter functionality',
    fn: () => {
      const csv = 'name,score\nAlex,10\nJamie,5\nSam,15';
      const result = parseCSV(csv);
      const filtered = result.filter((row) => row.score >= 10);
      assertEqual(filtered.length, 2);
      assertEqual(filtered[0].name, 'Alex');
      assertEqual(filtered[1].name, 'Sam');
    },
  },
  {
    name: 'aggregation helpers',
    fn: () => {
      const csv = 'team,score\nA,10\nB,20\nA,30';
      const result = parseCSV(csv);
      assertEqual(result.sum('score'), 60);
      assertEqual(result.average('score'), 20);
      assertEqual(result.count(), 3);
      const groups = result.groupBy('team');
      assertEqual(groups.get('A')?.length ?? 0, 2);
      assertEqual(groups.get('B')?.length ?? 0, 1);
    },
  },
  {
    name: 'edge cases',
    fn: () => {
      const empty = parseCSV('');
      assertEqual(empty.rows.length, 0);
      assertEqual(empty.headers.length, 0);
      assertEqual(empty.errors.length, 0);

      const single = parseCSV('value\n777');
      assertEqual(single.rows.length, 1);
      assertEqual(single.rows[0].value, 777);

      const oneColumnLarge = parseCSV('blob\n' + 'a'.repeat(5000));
      assertEqual(oneColumnLarge.rows[0].blob, 'a'.repeat(5000));
    },
  },
];

for (const test of tests) {
  try {
    test.fn();
    console.log(`✅ ${test.name}`);
  } catch (error) {
    console.error(`❌ ${test.name} failed:`, error);
    process.exit(1);
  }
}

console.log('All tests passed!');
